type FieldValidator = 
  | { type: 'string'; minLength?: number; maxLength?: number; pattern?: RegExp }
  | { type: 'number'; min?: number; max?: number }
  | { type: 'boolean' }
  | { type: 'array'; items: FieldValidator }
  | { type: 'object'; schema: Schema };

type Schema = Record<string, FieldValidator & { required?: boolean }>;

function validateField(
  value: unknown,
  validator: FieldValidator,
  path: string
): ValidationError[] {
  const errors: ValidationError[] = [];
  if (validator.type === 'string') {
    if (typeof value !== 'string') {
      errors.push({ path, message: 'Expected string' });
    } else if (validator.minLength && value.length < validator.minLength) {
      errors.push({ path, message: `Minimum length is ${validator.minLength}` });
    }
  }
  return errors;
}
